import React, { useState } from 'react';
import { useStripe, useElements, CardElement } from '@stripe/react-stripe-js';
import './payment.css';

const API_BASE_URL = 'https://e-nutritionist-08e05a1c6652.herokuapp.com'; // Your actual backend URL
const API_Local_Host = "http://localhost:3000";


const CheckoutForm = ({ bookingId, amount, onPaymentSuccess }) => {
  const stripe = useStripe();
  const elements = useElements();
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (event) => {
    event.preventDefault();

    if (!stripe || !elements) {
      return;
    }

    setLoading(true);
    setError(null);

    const cardElement = elements.getElement(CardElement);

    try {
      // Step 1: Create Payment Intent on the server-side
      const paymentIntentResponse = await fetch(`${API_BASE_URL}/create_payment_intent`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          booking_id: bookingId,
          amount: amount, // Amount in cents
        }),
      });

      if (!paymentIntentResponse.ok) {
        throw new Error('Failed to create Payment Intent');
      }

      const { clientSecret } = await paymentIntentResponse.json();

      // Step 2: Confirm the Payment with Stripe using the Payment Intent's client secret
      const { paymentIntent, error: stripeError } = await stripe.confirmCardPayment(clientSecret, {
        payment_method: {
          card: cardElement,
        },
      });

      if (stripeError) {
        setError(`Payment failed: ${stripeError.message}`);
        setLoading(false);
        return;
      }

      if (paymentIntent.status === 'succeeded') {
        onPaymentSuccess(paymentIntent);
      } else {
        setError('Payment processing error, please try again.');
      }
    } catch (error) {
      setError(`Payment failed: ${error.message}`);
    }

    setLoading(false);
  };

  return (
    <form className="payment-form" onSubmit={handleSubmit}>
      <h2>Complete Your Payment</h2>
      <CardElement className="StripeElement" />
      <button type="submit" disabled={!stripe || loading}>
        {loading ? 'Processing...' : 'Pay Now'}
      </button>
      {error && <div className="error-message">{error}</div>}
    </form>
  );
};

export default CheckoutForm;
